 65→ForStatement
 66→  = stmt:ForBlock { return stmt; }
 67→
 68→ForBlock
 69→  = "for" __ variable:Ident __ "in" __ iterable:Expression _ "{" _ body:StatementList _ "}" {
 70→      return { type: 'ForStatement', variable, iterable, body, location: location() };
 71→    }
 72→
 73→IfStatement
 74→  = "if" __ condition:Condition _ "{" _ consequent:StatementList _ "}"
 75→    alt:(_ "else" _ "{" _ body:StatementList _ "}" { return body; })? {
 76→      return { type: 'IfStatement', condition, consequent, alternate: alt || [], location: location() };
 77→    }
